seed_invoice AS (
  INSERT INTO "invoice" (
    id, "organizationId", "invoiceNumber", title, status, "recipientName",
    "recipientEmail", "issueDate", "dueDate", items, subtotal, "discountAmount",
    "taxRate", "taxAmount", "totalAmount", currency,
    "paymentStatus", "paymentMethod", "saleId", notes, activities, attachments,
    "createdById", "updatedById", "createdAt", "updatedAt"
  )
  SELECT
    ('c' || substr(md5(random()::text || clock_timestamp()::text), 1, 24)),
    s."organizationId",
    'INV/OPERO/2026/' || lpad(s.i::text, 4, '0'),
    'Invoice ' || s."saleNumber",
    CASE WHEN s.i % 4 = 0 THEN 'Paid' ELSE 'Unpaid' END,
    c.name,
    lower(replace(c.name, ' ', '.')) || '@contoh.co.id',
    NOW() - (s.i || ' days')::interval,
    NOW() + ((14 + s.i) || ' days')::interval,
    jsonb_build_array(jsonb_build_object('id', ('c' || substr(md5(random()::text || clock_timestamp()::text), 1, 24)), 'description', 'Tagihan penjualan ' || s.i, 'quantity', 1, 'unitPrice', total_amount, 'amount', total_amount)),
    total_amount / 1.11,
    0,
    11,
    total_amount - (total_amount / 1.11),
    total_amount,
    'IDR',
    CASE WHEN s.i % 4 = 0 THEN 'Paid' ELSE 'Unpaid' END,
    CASE WHEN s.i % 2 = 0 THEN 'Bank Transfer' ELSE 'QRIS' END,
    s.id,
    invoice_note,
    '[]'::jsonb,
    '[]'::jsonb,
    u."userId",
    u."userId",
    NOW(),
    NOW()
  FROM (
    SELECT id, "organizationId", "saleNumber", row_number() OVER (ORDER BY "saleNumber") AS i, 1000000 + (row_number() OVER (ORDER BY "saleNumber") * 275000) AS total_amount FROM seed_sale
  ) s
  JOIN (
    SELECT id, name, row_number() OVER (ORDER BY name) AS i FROM seed_contact
  ) c ON c.i = s.i
  CROSS JOIN tenant_user u
  CROSS JOIN LATERAL (
    SELECT (ARRAY[
      'Termin pembayaran 14 hari setelah invoice diterima.',
