INSERT INTO "tenant_activity" (
  id, "organizationId", module, action, "entityType", "entityName", description, "userId", "createdAt"
)
SELECT
  ('c' || substr(md5(random()::text || clock_timestamp()::text), 1, 24)),
  t.id,
  'SYSTEM',
  'SEED',
  'Database',
  'Seed data Indonesia',
  'Database fitur diisi ulang dengan 20 data per modul utama.',
  u."userId",
  NOW()
FROM selected_tenant t
CROSS JOIN tenant_user u;

COMMIT;
